--[[============================================================================
  MoonVeil Loader -- Instrumented Analysis Sandbox (Roblox executor edition)
  ---------------------------------------------------------------------------
  ЦЕЛЬ: безопасно НАБЛЮДАТЬ за поведением обфусцированного VM-загрузчика.
  Харнесс НЕ ходит в сеть, НЕ пишет файлы, НЕ трогает буфер обмена,
  НЕ телепортирует. Все опасные вызовы перехватываются, логируются и
  заменяются безвредными заглушками. Вторая стадия ПЕРЕХВАТЫВАЕТСЯ, НО НЕ
  ИСПОЛНЯЕТСЯ.

  !!! ЗАПУСКАТЬ ТОЛЬКО В ОДНОРАЗОВОЙ ВМ, ПОД МУСОРНЫМ АККАУНТОМ,
      БЕЗ ДОСТУПА К РЕАЛЬНЫМ ДАННЫМ. Executor = код исполняется в реальном
      процессе Roblox; при обходе anti-tamper это опасно. !!!

  ИСПОЛЬЗОВАНИЕ:
    1. Положите обфусцированный скрипт в рабочую папку экзекутора как
       "target.lua" (туда же, откуда работает readfile).
    2. Запустите этот файл экзекутором.
    3. Смотрите лог: [RESOLVE] [NET] [EXEC] [FS] [CLIP] [TP].
       Именно [NET] покажет URL, а [EXEC] -- исходник второй стадии.
============================================================================]]

local CONFIG = {
  target_path       = "target.lua",
  log_arg_maxlen    = 4000,
  dump_second_stage = true,
}

--// -------------------------------------------------------------------------
--// Логгер
--// -------------------------------------------------------------------------
local Log = {}
local _real_writefile = (getgenv and rawget(getgenv(), "writefile")) or writefile
local _real_appendfile = (getgenv and rawget(getgenv(), "appendfile")) or appendfile
local LOG_PATH = "moonveil_log.txt"
local _real_setclipboard = (getgenv and (rawget(getgenv(), "setclipboard") or rawget(getgenv(), "toclipboard"))) or setclipboard or toclipboard
local _alllog = ""
local _guiPush = nil
do
  local n = 0
  local _buf = ""
  local function stamp() n += 1; return string.format("#%04d", n) end
  local function trunc(s)
    if type(s) ~= "string" then return s end
    if #s > CONFIG.log_arg_maxlen then
      return s:sub(1, CONFIG.log_arg_maxlen) .. ("...[+%d bytes]"):format(#s - CONFIG.log_arg_maxlen)
    end
    return s
  end
  local function fmtval(v)
    local t = type(v)
    if t == "string" then return string.format("%q", trunc(v)) end
    if t == "table" then return "<table "..tostring(v)..">" end
    if t == "function" then return "<function>" end
    return tostring(v)
  end
  local function fmtargs(...)
    local parts = {}
    for i = 1, select("#", ...) do parts[i] = fmtval((select(i, ...))) end
    return table.concat(parts, ", ")
  end
  function Log.event(tag, msg, ...)
    local line = string.format("[%s] %s %s", tag, stamp(), msg)
    if select("#", ...) > 0 then line = line .. " :: args(" .. fmtargs(...) .. ")" end
    print(line)
    _alllog = _alllog .. line .. "\n"
    if _real_appendfile then
      pcall(_real_appendfile, LOG_PATH, line .. "\n")
    elseif _real_writefile then
      _buf = _buf .. line .. "\n"; pcall(_real_writefile, LOG_PATH, _buf)
    end
    if _guiPush then pcall(_guiPush, line) end
  end
  Log.trunc = trunc
end

function Log.copy()
  if _real_setclipboard then
    return (pcall(_real_setclipboard, _alllog))
  end
  return false
end
function Log.getAll() return _alllog end

--// -------------------------------------------------------------------------
--// Экранная панель лога (работает на мобильном Delta)
--// -------------------------------------------------------------------------
do
  local ok = pcall(function()
    local parent = (gethui and gethui()) or game:GetService("CoreGui")
    local gui = Instance.new("ScreenGui")
    gui.Name = "MoonVeilLog"; gui.ResetOnSpawn = false; gui.Parent = parent
    local frame = Instance.new("Frame")
    frame.Size = UDim2.new(0, 380, 0, 320); frame.Position = UDim2.new(0, 10, 0, 10)
    frame.BackgroundColor3 = Color3.fromRGB(15, 15, 20); frame.BackgroundTransparency = 0.1
    frame.Active = true; frame.Draggable = true; frame.Parent = gui
    local title = Instance.new("TextLabel")
    title.Size = UDim2.new(1, -72, 0, 26); title.BackgroundColor3 = Color3.fromRGB(40, 40, 55)
    title.Text = "MoonVeil log (тащи)"; title.TextColor3 = Color3.fromRGB(235, 235, 235)
    title.Font = Enum.Font.Code; title.TextSize = 14; title.Parent = frame
    local copyBtn = Instance.new("TextButton")
    copyBtn.Size = UDim2.new(0, 68, 0, 26); copyBtn.Position = UDim2.new(1, -68, 0, 0)
    copyBtn.BackgroundColor3 = Color3.fromRGB(70, 120, 70)
    copyBtn.Text = "Copy"; copyBtn.TextColor3 = Color3.fromRGB(240, 255, 240)
    copyBtn.Font = Enum.Font.Code; copyBtn.TextSize = 14; copyBtn.Parent = frame
    copyBtn.MouseButton1Click:Connect(function()
      local ok = Log.copy()
      copyBtn.Text = ok and "Copied!" or "No clip"
      task.delay(1.2, function() copyBtn.Text = "Copy" end)
    end)
    local scroll = Instance.new("ScrollingFrame")
    scroll.Size = UDim2.new(1, -8, 1, -32); scroll.Position = UDim2.new(0, 4, 0, 30)
    scroll.BackgroundTransparency = 1; scroll.ScrollBarThickness = 6
    scroll.CanvasSize = UDim2.new(0, 0, 0, 0); scroll.AutomaticCanvasSize = Enum.AutomaticSize.Y
    scroll.Parent = frame
    local layout = Instance.new("UIListLayout"); layout.SortOrder = Enum.SortOrder.LayoutOrder; layout.Parent = scroll
    local idx = 0
    _guiPush = function(text)
      idx += 1
      local lbl = Instance.new("TextLabel")
      lbl.Size = UDim2.new(1, 0, 0, 0); lbl.AutomaticSize = Enum.AutomaticSize.Y
      lbl.BackgroundTransparency = 1; lbl.Text = text; lbl.TextWrapped = true
      lbl.TextXAlignment = Enum.TextXAlignment.Left; lbl.TextColor3 = Color3.fromRGB(200, 255, 200)
      lbl.Font = Enum.Font.Code; lbl.TextSize = 12; lbl.LayoutOrder = idx; lbl.Parent = scroll
    end
  end)
  if not ok then _guiPush = nil end
end

