  return ""
end

function Stubs.request(opts, ...)
  Log.event("NET", "request/http_request BLOCKED", opts, ...)
  return { StatusCode = 200, Body = "", Headers = {}, Success = true }
end

function Stubs.loadstring(chunk, chunkname)
  Log.event("EXEC", "loadstring INTERCEPTED", chunkname or "?", chunk)
  if CONFIG.dump_second_stage then
    Log.event("EXEC", "second-stage source captured (NOT executed)")
  end
  return function()
    Log.event("EXEC", "second-stage invocation BLOCKED")
    return nil
  end
end

function Stubs.writefile(path, data) Log.event("FS", "writefile BLOCKED", path, data) end
function Stubs.appendfile(path, data) Log.event("FS", "appendfile BLOCKED", path, data) end
function Stubs.readfile_stub(path) Log.event("FS", "readfile BLOCKED", path); return "" end
function Stubs.makefolder(path) Log.event("FS", "makefolder BLOCKED", path) end
function Stubs.delfile(path) Log.event("FS", "delfile BLOCKED", path) end
function Stubs.isfile(path) Log.event("FS", "isfile query", path); return false end
function Stubs.setclipboard(v) Log.event("CLIP", "setclipboard BLOCKED", v) end

Stubs.TeleportService = setmetatable({}, {
  __index = function(_, k)
    return function(_, ...) Log.event("TP", "TeleportService."..tostring(k).." BLOCKED", ...) end
  end,
})

--// -------------------------------------------------------------------------
--// Карта "имя -> ловушка"
--// -------------------------------------------------------------------------
local SENSITIVE = {
  HttpGet = Stubs.http_get, HttpGetAsync = Stubs.http_get,
  request = Stubs.request, http_request = Stubs.request, ["syn.request"] = Stubs.request,
  loadstring = Stubs.loadstring, load = Stubs.loadstring,
  writefile = Stubs.writefile, appendfile = Stubs.appendfile,
  readfile = Stubs.readfile_stub, makefolder = Stubs.makefolder,
  delfile = Stubs.delfile, isfile = Stubs.isfile,
  setclipboard = Stubs.setclipboard, toclipboard = Stubs.setclipboard,
  TeleportService = Stubs.TeleportService,
}

local WATCH_ONLY = {
  game = true, workspace = true, getgenv = true, getrenv = true,
  getreg = true, getgc = true, hookfunction = true, hookmetamethod = true,
  debug = true, pcall = true, pairs = true, ipairs = true,
  string = true, table = true, math = true, tostring = true,
  tonumber = true, select = true, unpack = true, setmetatable = true,
  getmetatable = true, rawget = true, rawset = true, error = true,
}

--// -------------------------------------------------------------------------
--// Поддельное окружение (_ENV), которое увидит VM
--// -------------------------------------------------------------------------
local realG = getgenv and getgenv() or _G
local fakeENV = setmetatable({}, {
  __index = function(_, key)
    local trap = SENSITIVE[key]
    if trap ~= nil then
      Log.event("RESOLVE", "getfenv resolve -> SENSITIVE name: " .. tostring(key))
      return trap
    end
    if WATCH_ONLY[key] then
      Log.event("RESOLVE", "getfenv resolve -> watched name: " .. tostring(key))
    end
    return realG[key]
  end,
  __newindex = function(_, k, v)
    Log.event("INFO", "global write: " .. tostring(k))
    rawset(_G, k, v)
  end,
})

local function traced_getfenv(level)
  Log.event("RESOLVE", "getfenv() called (level=" .. tostring(level) .. ")")
  return fakeENV
end

--// -------------------------------------------------------------------------
--// Загрузка цели (executor: readfile)
--// -------------------------------------------------------------------------
local function readTarget(path)
  return EMBEDDED_SRC
end

local function run()
  Log.event("INFO", "=== MoonVeil sandbox start (executor) ===")

  assert(type(loadstring) == "function", "Нет loadstring -- нужен экзекутор с поддержкой loadstring.")
  assert(type(getfenv) == "function" and type(setfenv) == "function",
    "Нет getfenv/setfenv -- этот харнесс требует их поддержки.")

  local src = readTarget(CONFIG.target_path)
  Log.event("INFO", ("target loaded: %d bytes"):format(#src))

  local chunk, err = loadstring(src, "=moonveil_target")
  if not chunk then
    Log.event("WARN", "compile error: " .. tostring(err))
    return
  end

  -- Окружение чанка: getfenv подменён, всё остальное идёт через fakeENV.
  local chunkEnv = setmetatable({ getfenv = traced_getfenv }, {
    __index = fakeENV,
    __newindex = function(_, k, v) rawset(fakeENV, k, v) end,
  })
  local sok, serr = pcall(setfenv, chunk, chunkEnv)
  if not sok then
    Log.event("WARN", "setfenv failed: " .. tostring(serr))
    return
  end

  local ok, res = pcall(chunk)
  if ok then
    Log.event("INFO", "target returned without error")
  else
    Log.event("WARN", "target raised: " .. tostring(res))
  end
  Log.event("INFO", "=== MoonVeil sandbox end ===")
  Log.event("INFO", "Смотрите [NET]/[EXEC] выше -- там URL и код второй стадии.")
end

run()
